import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Latent Space — 2026-04-18","description":"","frontmatter":{"title":"Latent Space — 2026-04-18","date":"2026-04-18T00:00:00.000Z","source":"Latent Space","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-18-latent-space.md","filePath":"research/ai-news/2026-04/2026-04-18-latent-space.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-04/2026-04-18-latent-space.md"};function o(i,e,l,c,h,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔬-latent-space-—-2026-04-18" tabindex="-1">🔬 Latent Space — 2026-04-18 <a class="header-anchor" href="#🔬-latent-space-—-2026-04-18" aria-label="Permalink to &quot;🔬 Latent Space — 2026-04-18&quot;">​</a></h1><blockquote><p>swyx 開發者簡報，未公開專案 + 工程視角 來源：<a href="https://www.latent.space/feed" target="_blank" rel="noreferrer">Latent Space</a></p></blockquote><hr><h2 id="ainews-the-two-sides-of-openclaw" tabindex="-1"><a href="https://www.latent.space/p/ainews-the-two-sides-of-openclaw" target="_blank" rel="noreferrer">[AINews] The Two Sides of OpenClaw</a> <a class="header-anchor" href="#ainews-the-two-sides-of-openclaw" aria-label="Permalink to &quot;[[AINews] The Two Sides of OpenClaw](https://www.latent.space/p/ainews-the-two-sides-of-openclaw)&quot;">​</a></h2><p><em>🔬 Latent Space | 2026-04-18</em></p><p>In an opportune coinciding of big three letter conferences, the <a href="https://x.com/bilawalsidhu/status/2045291456630509709" target="_blank" rel="noreferrer">TED talk</a> and the <a href="https://www.youtube.com/watch?v=zgNvts_2TUE&amp;t=2087s&amp;pp=ygUVcGV0ZXIgc3RlaW5iZXJnZXIgdGVk" target="_blank" rel="noreferrer">AIE talks</a> of Peter Steinberger dropped today. To the general public, the inspiring story of OpenClaw was delightfully <a href="https://www.ted.com/talks/peter_steinberger_how_i_created_openclaw_the_breakthrough_ai_agent" target="_blank" rel="noreferrer">told onstage</a>, which recaps all the highs:</p><p>To the engineering audience, it was more sober, talking about the unprecedented levels of security incidents (60x more reports than curl, at least 20% of skill contributions malicious) and scaling issues involved in maintaining the fastest growing open source project in history:</p><p>An AMA moderated by me is included at the end.</p><p>Contrast them, thoughts welcome.</p><p>AI News for 4/16/2026-4/17/2026. We checked 12 subreddits, <a href="https://twitter.com/i/lists/1585430245762441216" target="_blank" rel="noreferrer">544 Twitters</a> and no further Discords. <a href="https://news.smol.ai/" target="_blank" rel="noreferrer">AINews’ website</a> lets you search all past issues. As a reminder, <a href="https://www.latent.space/p/2026" target="_blank" rel="noreferrer">AINews is now a section of Latent Space</a>. You can <a href="https://support.substack.com/hc/en-us/articles/8914938285204-How-do-I-subscribe-to-or-unsubscribe-from-a-section-on-Substack" target="_blank" rel="noreferrer">opt in/out</a> of email frequencies!</p><p>AI Twitter Recap</p><p>Anthropic’s Claude Opus 4.7 and Claude Design rollout</p><p>Claude Design launched as Anthropic’s first design/prototyping surface: <a href="https://x.com/claudeai/status/2045156267690213649" target="_blank" rel="noreferrer">@claudeai</a> announced Claude Design, a research-preview tool for generating prototypes, slides, and one-pagers from natural-language instructions, powered by Claude Opus 4.7. The launch immediately framed Anthropic as moving beyond chat/coding into design tooling; multiple observers called it a direct shot at Figma/Lovable/Bolt/v0, including <a href="https://x.com/Yuchenj_UW/status/2045158071950033063" target="_blank" rel="noreferrer">@Yuchenj_UW</a>, <a href="https://x.com/kimmonismus/status/2045162358004216134" target="_blank" rel="noreferrer">@kimmonismus</a>, and <a href="https://x.com/skirano/status/2045192705941106992" target="_blank" rel="noreferrer">@skirano</a>. The market reaction itself became part of the story, with <a href="https://x.com/Yuchenj_UW/status/2045161719547445426" target="_blank" rel="noreferrer">@Yuchenj_UW</a> and others noting Figma’s sharp drawdown after the announcement. Product details surfaced via <a href="https://x.com/TheRundownAI/status/2045176722476208454" target="_blank" rel="noreferrer">@TheRundownAI</a>: inline refinement, sliders, exports to Canva/PPTX/PDF/HTML, and handoff to Claude Code for implementation.</p><p>Opus 4.7 looks stronger overall, but the rollout was noisy: third-party benchmark posts were broadly favorable. <a href="https://x.com/arena/status/2045177492936532029" target="_blank" rel="noreferrer">@arena</a> put Opus 4.7 #1 in Code Arena, +37 over Opus 4.6 and ahead of non-Anthropic peers there; the same account also had it at #1 overall in Text Arena with category wins across coding and science-heavy domains <a href="https://x.com/arena/status/2045177497378316597" target="_blank" rel="noreferrer">here</a>. <a href="https://x.com/ArtificialAnlys/status/2045292578434875552" target="_blank" rel="noreferrer">@ArtificialAnlys</a> reported a near three-way tie at the top of its Intelligence Index—Opus 4.7 57.3, Gemini 3.1 Pro 57.2, GPT-5.4 56.8—while also placing Opus 4.7 first on GDPval-AA, their agentic benchmark. They also noted ~35% fewer output tokens than Opus 4.6 at higher score, and introduction of task budgets plus full removal of extended thinking in favor of adaptive reasoning. But user experience was mixed in the first 24 hours: <a href="https://x.com/VictorTaelin/status/2045139180359942462" target="_blank" rel="noreferrer">@VictorTaelin</a> reported regressions and context failures, <a href="https://x.com/emollick/status/2045147490316374414" target="_blank" rel="noreferrer">@emollick</a> said Anthropic had already improved adaptive thinking behavior by the next day, and <a href="https://x.com/alexalbert__/status/2045159041283064095" target="_blank" rel="noreferrer">@alexalbert__</a> confirmed that many initial bugs had been fixed. There were also complaints about product stability in Design itself from <a href="https://x.com/theo/status/2045310884717981987" target="_blank" rel="noreferrer">@theo</a> and account-level safety issues from the same account <a href="https://x.com/theo/status/2045317666383204423" target="_blank" rel="noreferrer">here</a>.</p><p>Cost/efficiency discussion became almost as important as raw quality: <a href="https://x.com/scaling01/status/2045160883010081237" target="_blank" rel="noreferrer">@scaling01</a> claimed ~10x fewer tokens for some ML problem runs versus prior high-end models while maintaining similar performance, while <a href="https://x.com/ArtificialAnlys/status/2045206342173086156" target="_blank" rel="noreferrer">@ArtificialAnlys</a> placed Opus 4.7 on the price/performance Pareto frontier for both text and code. Not every benchmark agreed on absolute leadership—e.g. <a href="https://x.com/scaling01/status/2045178622617498084" target="_blank" rel="noreferrer">@scaling01</a> noted it still trails Gemini 3.1 Pro and GPT-5.4 on LiveBench—but the consensus from these posts is that Anthropic materially improved the model’s agentic utility and efficiency.</p><p>Computer use, coding agents, and harness design</p><p>Computer-use UX is becoming a mainstream product category: OpenAI’s Codex desktop/computer-use updates drew unusually strong practitioner reactions. <a href="https://x.com/reach_vb/status/2045151640802771394" target="_blank" rel="noreferrer">@reach_vb</a> called subagents + computer use “pretty close” to AGI in practical feel; <a href="https://x.com/kr0der/status/2045154074337710136" target="_blank" rel="noreferrer">@kr0der</a>, <a href="https://x.com/HamelHusain/status/2045191726495846459" target="_blank" rel="noreferrer">@HamelHusain</a>, <a href="https://x.com/mattrickard/status/2045218583882633412" target="_blank" rel="noreferrer">@mattrickard</a>, and <a href="https://x.com/matvelloso/status/2045209294942142860" target="_blank" rel="noreferrer">@matvelloso</a> all emphasized that Codex Computer Use is not just flashy but fast, able to drive Slack, browser flows, and arbitrary desktop apps, and may be the first genuinely usable computer-use platform for enterprise legacy software. <a href="https://x.com/gdb/status/2045375289560007029" target="_blank" rel="noreferrer">@gdb</a> explicitly framed Codex as becoming a full agentic IDE.</p><p>The field is converging on “simple harness, strong evals, model-agnostic scaffolding”: several high-signal posts argued that reliability gains now come more from harnesses than from chasing the very largest models. <a href="https://x.com/AsfiShaheen/status/2045072599508508914" target="_blank" rel="noreferrer">@AsfiShaheen</a> described a three-stage financial analyst pipeline—router / lane / analyst—with strict context boundaries and gold sets for each stage, arguing that many bugs were actually instruction/interface bugs. <a href="https://x.com/AymericRoucher/status/2045176781414527305" target="_blank" rel="noreferrer">@AymericRoucher</a> extracted the same lesson from the leaked Claude Code harness: simple planning constraints plus a cleaner representation layer outperform “fancy AI scaffolds.” <a href="https://x.com/raw_works/status/2045208764509470742" target="_blank" rel="noreferrer">@raw_works</a> showed an even starker example: Qwen3-8B scored 33/507 on LongCoT-Mini with dspy.RLM, versus 0/507 vanilla, arguing the scaffold—not fine-tuning—did “100% of the lifting.” LangChain shipped more of these patterns into product: <a href="https://x.com/sydneyrunkle/status/2045209395881980276" target="_blank" rel="noreferrer">@sydneyrunkle</a> added subagent support to deepagents deploy, and <a href="https://x.com/whoiskatrin/status/2045139949939200284" target="_blank" rel="noreferrer">@whoiskatrin</a> announced memory primitives in the Agents SDK.</p><p>Open-source agent stacks continue to proliferate: Hermes Agent remained a focal point. Community ecosystem overviews from <a href="https://x.com/GitTrend0x/status/2045142797439922337" target="_blank" rel="noreferrer">@GitTrend0x</a> highlighted derivatives like Hermes Atlas, Hermes-Wiki, HUDs, and control dashboards. <a href="https://x.com/ollama/status/2045282803387158873" target="_blank" rel="noreferrer">@ollama</a> then shipped native Hermes support via ollama launch hermes, which <a href="https://x.com/NousResearch/status/2045304840645939304" target="_blank" rel="noreferrer">@NousResearch</a> amplified. Nous and Kimi also launched a $25k Hermes Agent Creative Hackathon <a href="https://x.com/NousResearch/status/2045225469088326039" target="_blank" rel="noreferrer">@NousResearch</a>, signaling a push from coding/productivity into creative agent workflows.</p><p>Agent research: self-improvement, monitoring, web skills, and evaluation</p><p>A cluster of papers pushed agent robustness and continual improvement forward: <a href="https://x.com/omarsar0/status/2045139481779696027" target="_blank" rel="noreferrer">@omarsar0</a> summarized Cognitive Companion, which monitors reasoning degradation either with an LLM judge or a hidden-state probe. The headline result is notable: a logistic-regression probe on layer-28 hidden states can detect degradation with AUROC 0.840 at zero measured inference overhead, while the LLM-monitor version cuts repetition 52–62% with ~11% overhead. Separate work on web agents from <a href="https://x.com/dair_ai/status/2045139481892880892" target="_blank" rel="noreferrer">@dair_ai</a> described WebXSkill, where agents extract reusable skills from trajectories, yielding up to +9.8 points on WebArena and 86.1% on WebVoyager in grounded mode. And <a href="https://x.com/omarsar0/status/2045241905227915498" target="_blank" rel="noreferrer">@omarsar0</a> also highlighted Autogenesis, a protocol for agents to identify capability gaps, propose improvements, validate them, and integrate working changes without retraining.</p><p>Open-world evals are becoming a serious theme: several posts argued current benchmarks are too narrow. <a href="https://x.com/CUdudec/status/2045139195220431022" target="_blank" rel="noreferrer">@CUdudec</a> endorsed open-world evaluations for long-horizon, open-ended settings; <a href="https://x.com/ghadfield/status/2045245020429570505" target="_blank" rel="noreferrer">@ghadfield</a> connected this to regulation and “economy of agents” questions; and <a href="https://x.com/PKirgis/status/2045265295649231354" target="_blank" rel="noreferrer">@PKirgis</a> discussed CRUX, a project for regular open-world evaluations of AI agents in messy real environments. On the measurement side, <a href="https://x.com/NandoDF/status/2045063560716296450" target="_blank" rel="noreferrer">@NandoDF</a> proposed broad NLL/perplexity-based eval suites over out-of-training-domain books/articles across 2500 topic buckets, though that sparked debate about whether perplexity remains informative after RLHF/post-training from <a href="https://x.com/eliebakouch/status/2045115926123520100" target="_blank" rel="noreferrer">@eliebakouch</a>, <a href="https://x.com/teortaxesTex/status/2045139476972745120" target="_blank" rel="noreferrer">@teortaxesTex</a>, and others.</p><p>Document/OCR and retrieval evals also got more agent-centric: <a href="https://x.com/llama_index/status/2045145054772183128" target="_blank" rel="noreferrer">@llama_index</a> expanded on ParseBench, an OCR benchmark centered on content faithfulness with 167K+ rule-based tests across omissions, hallucinations, and reading-order violations—explicitly reframing the bar from “human-readable” to “reliable enough for an agent to act on.” In retrieval, <a href="https://x.com/Julian_a42f9a/status/2045200413402493064" target="_blank" rel="noreferrer">@Julian_a42f9a</a> noted new work showing late-interaction retrieval representations can substitute for raw document text in RAG, suggesting some RAG pipelines may be able to bypass full-text reconstruction.</p><p>Open models, local inference, and inference systems</p><p>Qwen3.6 local/quantized workflows were a practical bright spot: <a href="https://x.com/victormustar/status/2045068986446958899" target="_blank" rel="noreferrer">@victormustar</a> shared a concrete llama.cpp + Pi setup for Qwen3.6-35B-A3B as a local agent stack, emphasizing how viable local agentic systems now feel. Red Hat quickly followed with an NVFP4-quantized Qwen3.6-35B-A3B checkpoint <a href="https://x.com/RedHat_AI/status/2045153791402520952" target="_blank" rel="noreferrer">@RedHat_AI</a>, reporting preliminary GSM8K Platinum 100.69% recovery, and <a href="https://x.com/danielhanchen/status/2045169369723064449" target="_blank" rel="noreferrer">@danielhanchen</a> benchmarked dynamic quants, claiming many Unsloth quants sit on the Pareto frontier for KLD vs disk space.</p><p>Consumer-hardware inference keeps improving: <a href="https://x.com/RisingSayak/status/2045114073000657316" target="_blank" rel="noreferrer">@RisingSayak</a> announced work with PyTorch/TorchAO enabling offloading with FP8 and NVFP4 quants without major latency penalties, explicitly targeting consumer GPU users constrained by memory. Apple-side local inference also got a showcase with <a href="https://x.com/googlegemma/status/2045204738720084191" target="_blank" rel="noreferrer">@googlegemma</a>, which demoed Gemma 4 running fully offline on iPhone with long context.</p><p>Inference infra updates worth noting: <a href="https://x.com/vllm_project/status/2045381618928582995" target="_blank" rel="noreferrer">@vllm_project</a> highlighted MORI-IO KV Connector with AMD/EmbeddedLLM, claiming 2.5× higher goodput on a single node via a PD-disaggregation-style connector. Cloudflare continued its agent/AI-platform push with isitagentready.com <a href="https://x.com/Cloudflare/status/2045126394418503846" target="_blank" rel="noreferrer">@Cloudflare</a>, Flagship feature flags <a href="https://x.com/fayazara/status/2045133183575113771" target="_blank" rel="noreferrer">@fayazara</a>, and shared compression dictionaries yielding dramatic payload reductions such as 92KB → 159 bytes in one example <a href="https://x.com/ackriv/status/2045177696506794336" target="_blank" rel="noreferrer">@ackriv</a>.</p><p>AI for science, medicine, and infrastructure</p><p>Scientific discovery and personalized health were prominent applied themes: <a href="https://x.com/JoyHeYueya/status/2045147082546462860" target="_blank" rel="noreferrer">@JoyHeYueya</a> and <a href="https://x.com/Anikait_Singh_/status/2045149764636094839" target="_blank" rel="noreferrer">@Anikait_Singh_</a> posted about insight anticipation, where models generate a downstream paper’s core contribution from its “parent” papers; the latter introduced GIANTS-4B, an RL-trained model that reportedly beats frontier models on this task. On the health side, <a href="https://x.com/SRSchmidgall/status/2045023895041061353" target="_blank" rel="noreferrer">@SRSchmidgall</a> shared a biomarker-discovery system over wearable data whose first finding was that “late-night doomscrolling” predicts depression severity with ρ=0.177, p&lt;0.001, n=7,497—notable because the model itself named the feature. Separately, <a href="https://x.com/patrickc/status/2045164908912968060" target="_blank" rel="noreferrer">@patrickc</a> argued current coding agents are already highly useful for personalized genome interpretation, describing &lt;$100 analysis runs that surfaced a roughly 30× elevated melanoma predisposition plus follow-on interventions.</p><p>Large-scale compute buildout remains a core meta-story: <a href="https://x.com/EpochAIResearch/status/2045258390147088764" target="_blank" rel="noreferrer">@EpochAIResearch</a> surveyed all 7 US Stargate sites and concluded the project appears on track for 9+ GW by 2029, comparable to New York City peak demand. <a href="https://x.com/gdb/status/2045279841482928271" target="_blank" rel="noreferrer">@gdb</a> framed Stargate as infrastructure for a “compute-powered economy,” while <a href="https://x.com/kimmonismus/status/2045206835238441332" target="_blank" rel="noreferrer">@kimmonismus</a> put today’s annual global datacenter capex at roughly 5–7 Manhattan Projects per year in inflation-adjusted terms.</p><p>Top tweets (by engagement)</p><p>Claude Design / Anthropic product expansion: <a href="https://x.com/claudeai/status/2045156267690213649" target="_blank" rel="noreferrer">@claudeai launches Claude Design</a>, by far the day’s biggest pure-AI product launch signal.</p><p>Model benchmarking / rankings: <a href="https://x.com/ArtificialAnlys/status/2045292578434875552" target="_blank" rel="noreferrer">@ArtificialAnlys on Opus 4.7 tying for #1 overall and leading GDPval-AA</a>.</p><p>Coding agents / computer use: <a href="https://x.com/cursor_ai/status/2045236540784492845" target="_blank" rel="noreferrer">@cursor_ai doubles Composer 2 limits in the new agents window</a> and <a href="https://x.com/HamelHusain/status/2045191726495846459" target="_blank" rel="noreferrer">@HamelHusain on Codex Computer Use</a>.</p><p>Open-source agents: <a href="https://x.com/ollama/status/2045282803387158873" target="_blank" rel="noreferrer">@ollama ships native Hermes Agent support</a>.</p><p>Applied AI in medicine: <a href="https://x.com/patrickc/status/2045164908912968060" target="_blank" rel="noreferrer">@patrickc on coding agents for genome analysis and personalized prevention</a>.</p><p>Infra / power scaling: <a href="https://x.com/EpochAIResearch/status/2045258390147088764" target="_blank" rel="noreferrer">@EpochAIResearch on Stargate’s 9+ GW trajectory</a>.</p><p>AI Reddit Recap</p><p>/r/LocalLlama + /r/localLLM Recap</p><ol><li>Qwen3.6 Model Launch and Features</li></ol><p><a href="https://www.latent.space/p/ainews-the-two-sides-of-openclaw" target="_blank" rel="noreferrer"> Read more </a></p><hr>',42)])])}const f=a(s,[["render",o]]);export{u as __pageData,f as default};
